<template>
  <div>
    <!-- Mobile Menu -->
    <div class="icons-wrapper">
      <div>
        <img src="../assets/main/support-mobile.svg" />
      </div>
      <div @click="toggleRightSidebar">
        <img src="../assets/main/chat-mobile.svg" />
      </div>
    </div>
    <div class="mobile-menu d-flex align-items-center justify-content-between">
      <div class="mobile-item" @click="toggleSidebar">
        <div>
          <img src="../assets/main/menu-mobile.svg" />
        </div>
        <span>Меню</span>
      </div>
      <div class="mobile-item" @click="toggleSection('bonuses')">
        <div>
          <img src="../assets/main/bonus-menu.svg" />
        </div>
        <span>Бонусы</span>
      </div>
      <div class="mobile-item" @click="toggleSection('games')">
        <div>
          <img src="../assets/main/games-menu.svg" />
        </div>
        <span>Игры</span>
      </div>
      <div class="mobile-item" @click="toggleSection('bets')">
        <div>
          <img src="../assets/main/pools.svg" />
        </div>
        <span>Ставки</span>
      </div>
      <div class="mobile-item profile" @click="toggleAccount" v-if="isAuthenticated">
        <div>
          <img src="../assets/main/profile.svg" />
        </div>
        <span>Профиль</span>
      </div>
    </div>

    <!-- Sections -->
    <div v-if="activeSection" class="mobile-sections" @click.self="closeSections">
      <div v-if="activeSection === 'bonuses'" class="section bonuses">
        <div class="section-content">
          <div class="section-item" v-for="item in bonusItems" :key="item.id">
            <img :src="item.img" class="img-fluid w-100" />
          </div>
        </div>
      </div>
      <div v-if="activeSection === 'games'" class="section games">
        <div class="section-content">
          <div class="section-item" v-for="item in gameItems" :key="item.id">
            <img :src="item.img" class="img-fluid w-100" />
          </div>
        </div>
      </div>
      <div v-if="activeSection === 'bets'" class="section bets">
        <div class="section-content">
          <div class="section-item" v-for="item in betItems" :key="item.id">
            <img :src="item.img" class="img-fluid w-100" />
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
export default {
  name: 'MobileHeader',
  props: {
    collapsed: {
      type: Boolean,
      default: false
    },
    isAuthenticated: {
      type: Boolean,
      required: true
    },
    expandedAccount: {
      type: Boolean,
      default: false
    },
    isRightSidebarCollapsed: {
      type: Boolean,
      default: false
    }
  },
  data() {
    return {
      activeSection: null,
      bonusItems: [
        { id: 1, img: '/winmove/img/hello-bonus.svg' },
        { id: 2, img: '/winmove/img/hello-bonus-2.svg' },
        { id: 3, img: '/winmove/img/hello-bonus.svg' }
      ],
      gameItems: [
        { id: 1, img: '/winmove/img/crush-bottom.svg' },
        { id: 2, img: '/winmove/img/soon-2.svg' },
        { id: 3, img: '/winmove/img/crush-bottom.svg' }
      ],
      betItems: [
        { id: 1, img: '/winmove/img/cs.svg' },
        { id: 2, img: '/winmove/img/cs.svg' },
        { id: 3, img: '/winmove/img/cs.svg' }
      ]
    };
  },
  methods: {
    toggleSidebar() {
      this.$emit('toggle-sidebar', !this.collapsed);
    },
    toggleAccount() {
      this.$emit('toggle-account', !this.expandedAccount);
    },
    toggleRightSidebar() {
      this.$emit('toggle-right-sidebar', !this.isRightSidebarCollapsed);
    },
    toggleSection(section) {
      this.activeSection = this.activeSection === section ? null : section;
    },
    closeSections() {
      this.activeSection = null;
    }
  }
}
</script>

<style lang="scss" scoped>
.mobile-menu {
  position: fixed;
    width: 90%;
    background: #1A1B1D;
    padding: 5px 25px;
    border-radius: 50px;
    bottom: 15px;
    border: 1px solid #232426;
    z-index: 1000;
    margin: 0 auto;
    left: 5%;
}

.mobile-item img, .mobile-item span {
  text-align: center;
  display: block;
}

.mobile-item img {
  margin: 0 auto;
}

.mobile-item > div {
  border-radius: 50%;
  padding: 10px 8px;
  margin: 12px 0;
  height: 37px;
}
.mobile-item.profile > div {
  margin:0;
  height: inherit;
}
.mobile-item:hover > div, .mobile-item:focus > div, .mobile-item:active > div {
  background: #FDF74B;
}

.mobile-item.profile img {
  margin: 0 auto;
  padding: 0;
  border-radius: 50%;
}

.mobile-item.profile:hover > div, .mobile-item.profile:focus > div, .mobile-item.profile:active > div {
  background: transparent;
}

.mobile-item.profile:hover img, .mobile-item.profile:focus img, .mobile-item.profile:active img, .mobile-item.profile img {
  background: #FDF74B;
}

.mobile-item span {
  font-family: "Strapel bold";
  color: #717171;
  font-size: 11px;
  text-align: center;
  margin-top: 5px;
}

.mobile-sections {
  position: fixed;
  left: 0;
  right: 0;
  bottom: 100px;
  background: transparent;
  z-index: 1001;
  overflow: hidden;
}

.section {
  display: flex;
  flex-direction: column;
  padding: 15px;
  height: 100%;
}

.section-content {
  display: flex;
  overflow-x: scroll;
  white-space: nowrap;
  padding: 5px 0;
}

.section-content::-webkit-scrollbar {
  display: none;  /* Hide scrollbar in WebKit browsers */
}

.section-item {
  padding: 0;
  margin-right: 10px;
  border-radius: 0;
  flex: 0 0 auto;
  width: calc(50% - 5%);
}
.icons-wrapper {
  position: fixed;
    bottom: 100px;
    right: 5%;
    z-index: 1001;
}
.icons-wrapper > div {
  background: rgb(21 22 24 / 70%);
    border: 1px solid;
    border-color: rgb(69 69 69 / 47%);
    border-radius: 50%;
    padding: 8px 11px;
    margin-bottom: 15px;
}
</style>
